const item = $input.item.json;

function buildFullLinkedin(url) {
  if (!url) return "";
  url = url.trim().toLowerCase();
  if (!url.startsWith("http")) url = "https://" + url;
  url = url.replace("linkedin.com/", "www.linkedin.com/").replace("www.www.", "www.");
  return url.replace(/\/$/, "").split("?")[0];
}

const linkedinUrl = buildFullLinkedin(item.company_linkedin_url || "");

return {
  json: {
    input_linkedin_url:   item.company_linkedin_url || "",
    input_domain:         item.domain || item.company_domain || "",
    input_company_name:   item.company_name || "",
    row_number:           item.row_number || $itemIndex + 1,
    apollo_linkedin_url:  linkedinUrl
  }
};

const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const resp = items[i].json;
  const prev = $('Build Apollo Company Payload').all()[i]?.json || {};
  results.push({
    json: {
      input_linkedin_url:  prev.input_linkedin_url  || "",
      input_domain:        prev.input_domain        || "",
      input_company_name:  prev.input_company_name  || "",
      row_number:          prev.row_number           || (i + 1),
      apollo_linkedin_url: prev.apollo_linkedin_url || "",
      organizations:       resp.organizations       || [],
      total_entries:       resp.total_entries        || 0
    }
  });
}

return results;

const item = $input.item.json;
const org = (item.organizations && item.organizations.length > 0)
            ? item.organizations[0] : {};

return {
  json: {
    input_linkedin_url:   item.input_linkedin_url   || "",
    company_linkedin_url: org.linkedin_url          || item.input_linkedin_url || "",
    company_name:         org.name                  || item.input_company_name || "",
    domain:               org.primary_domain        || item.input_domain       || "",
    industry:             org.industry              || "",
    company_size:         String(org.estimated_num_employees || ""),
    location:             [org.city, org.state, org.country].filter(Boolean).join(", "),
    company_id:           org.id                    || "",
    apollo_org_id:        org.id                    || "",
    phone:                org.phone                 || "",
    revenue:              org.organization_revenue_printed || "",
    founded_year:         String(org.founded_year   || ""),
    data_source:          "apollo",
    enriched_at:          new Date().toISOString(),
    row_number:           item.row_number           || ""
  }
};

const seen = new Set();
const items = $input.all();

const unique = items.filter(item => {
  const key = item.json.apollo_org_id?.trim() ||
              item.json.company_linkedin_url?.trim() ||
              item.json.company_id?.trim() || "";
  if (!key || seen.has(key)) return false;
  seen.add(key);
  return true;
});

return unique;

const item = $input.item.json;
const companyData = $('Normalize Apollo Company').item.json;

function buildFullLinkedin(url) {
  if (!url) return "";
  url = url.trim().toLowerCase();
  if (!url.startsWith("http")) url = "https://" + url;
  url = url.replace("linkedin.com/", "www.linkedin.com/").replace("www.www.", "www.");
  return url.replace(/\/$/, "").split("?")[0];
}

const linkedinUrl = buildFullLinkedin(
  companyData.company_linkedin_url || companyData.input_linkedin_url || ""
);

return {
  json: {
    company_linkedin_url: companyData.company_linkedin_url || "",
    company_name:         companyData.company_name         || "",
    company_id:           companyData.company_id           || "",
    apollo_org_id:        companyData.apollo_org_id        || "",
    domain:               companyData.domain               || "",
    industry:             companyData.industry             || "",
    company_size:         companyData.company_size         || "",
    company_location:     companyData.location             || "",
    data_source_company:  "apollo",
    row_number:           companyData.row_number           || item.row_number || "",
    apollo_people_payload: {
      q_organization_linkedin_profile_url: linkedinUrl,
      person_seniorities: ["founder", "c_suite", "vp", "head", "director"],
      page: 1,
      per_page: 5
    }
  }
};

const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const resp = items[i].json;
  const context = $('Restore Context + Build People Payload').all()[i]?.json || {};
  const people = resp.people || [];

  if (people.length === 0) {
    results.push({
      json: {
        ...context,
        people_found: false,
        reason: "No senior people found in Apollo"
      }
    });
    continue;
  }

  for (const person of people) {
    results.push({
      json: {
        ...context,
        people_found:    true,
        person_name:     person.name || [person.first_name, person.last_name].filter(Boolean).join(" ") || "",
        title:           person.title     || "",
        seniority:       person.seniority || "",
        linkedin_url:    person.linkedin_url || "",
        person_linkedin: person.linkedin_url || ""
      }
    });
  }
}

return results;

const item = $input.item.json;
const p = item.person || {};

const primaryEmail = (p.email || "").trim();
const phone = (p.phone_numbers && p.phone_numbers.length > 0)
              ? p.phone_numbers[0].sanitized_number || ""
              : "";

return {
  json: {
    company_linkedin_url: item.company_linkedin_url || "",
    company_name:         p.organization?.name || item.company_name || "",
    company_id:           p.organization_id    || item.company_id   || "",
    domain:               item.domain          || "",
    company_industry:     item.company_industry || item.industry    || "",
    company_size:         item.company_size     || "",
    company_location:     item.company_location || "",
    data_source_company:  item.data_source_company || "apollo",
    person_name:          p.name || [p.first_name, p.last_name].filter(Boolean).join(" ") || item.person_name || "",
    title:                p.title     || item.title     || "",
    seniority:            p.seniority || item.seniority || "",
    email:                primaryEmail,
    all_emails:           JSON.stringify(p.emails || []),
    phone:                phone,
    linkedin_url:         p.linkedin_url || item.linkedin_url || item.person_linkedin || "",
    location:             [p.city, p.state, p.country].filter(Boolean).join(", "),
    data_source_person:   "apollo",
    enriched_at:          new Date().toISOString(),
    row_number:           item.row_number || ""
  }
};

