const d = $json;
return {
  json: {
    company_linkedin_url: d.company_linkedin_url || "",
    company_name:         d.company_name || "",
    company_id:           d.company_id   || "",
    person_name:          d.person_name  || "",
    title:                d.title        || "",
    seniority:            d.seniority    || "",
    linkedin_url:         d.linkedin_url || "",
    email_status:         "not_found",
    reason:               "Person found in Apollo but no email available",
    apollo_tried:         true,
    data_source_person:   d.data_source_person || "apollo",
    failed_at:            new Date().toISOString(),
    row_number:           d.row_number    || ""
  }
};

const staticData = $getWorkflowStaticData('global');

if (!staticData.masterLeads) staticData.masterLeads = [];
if (!staticData.batchCount)  staticData.batchCount  = 0;

staticData.batchCount += 1;

const seen = new Set(
  staticData.masterLeads.map(r => r.dedup_key).filter(Boolean)
);

const items = $input.all();

for (const item of items) {
  const d = item.json;

  if (!d.company_linkedin_url || !d.company_name || !d.person_name) continue;
  if (d.reason) continue;

  const key = d.email?.trim() ||
              d.linkedin_url?.trim() ||
              (d.person_name + "_" + d.company_name)
              .toLowerCase().replace(/\s+/g, "_");

  if (!key || seen.has(key)) continue;
  seen.add(key);

  staticData.masterLeads.push({
    company_linkedin_url: d.company_linkedin_url || "",
    company_name:         d.company_name         || "",
    company_id:           d.company_id           || "",
    domain:               d.domain               || "",
    industry:             d.industry             || "",
    company_size:         d.company_size         || "",
    company_location:     d.company_location     || "",
    data_source_company:  d.data_source_company  || "",
    person_name:          d.person_name          || "",
    title:                d.title                || "",
    seniority:            d.seniority            || "",
    email:                d.email                || "",
    all_emails:           (d.all_emails || "").substring(0, 500),
    phone:                d.phone                || "",
    person_linkedin_url:  d.linkedin_url         || "",
    person_location:      d.location             || "",
    data_source_person:   d.data_source_person   || "",
    enriched_at:          d.enriched_at          || "",
    dedup_key:            key
  });
}

const isLastBatch  = $node["Loop Over Items"].context.noItemsLeft;
const isCheckpoint = (staticData.batchCount % 10 === 0) || isLastBatch;

if (isLastBatch) staticData.batchCount = 0;

console.log(
  `Batch #${staticData.batchCount} | Accumulated: ${staticData.masterLeads.length}` +
  ` | Checkpoint: ${isCheckpoint} | Last: ${isLastBatch}`
);

return [{ json: {
  status:            'accumulated',
  count:             staticData.masterLeads.length,
  is_last_batch:     isLastBatch,
  should_checkpoint: isCheckpoint
}}];

const staticData = $getWorkflowStaticData('global');
const newLeads = staticData.masterLeads || [];
staticData.masterLeads = [];

const COLUMNS = [
  'company_linkedin_url','company_name','company_id','domain',
  'industry','company_size','company_location','data_source_company',
  'person_name','title','seniority','email','all_emails',
  'phone','person_linkedin_url','person_location',
  'data_source_person','enriched_at','dedup_key'
];

function cleanRow(raw) {
  const cleaned = {};
  for (const [key, val] of Object.entries(raw)) {
    const clean_key = key.replace(/[\ufeff\ufffe]/g, '').trim();
    if (cleaned[clean_key] && !val) continue;
    cleaned[clean_key] = val || '';
  }
  const out = {};
  for (const col of COLUMNS) { out[col] = cleaned[col] || ''; }
  return out;
}

const existingRows = $input.all()
  .map(item => cleanRow(item.json))
  .filter(row => row.company_name);

console.log('Existing rows from Drive:', existingRows.length, '| New leads:', newLeads.length);

if (newLeads.length === 0 && existingRows.length === 0) {
  return [{ json: { status: 'no_leads' } }];
}

const cleanedNew = newLeads.map(r => cleanRow(r));
const newKeys = new Set(cleanedNew.map(r => r.dedup_key).filter(Boolean));

const merged = [
  ...existingRows.filter(r => !r.dedup_key || !newKeys.has(r.dedup_key)),
  ...cleanedNew
];

console.log('Merged total:', merged.length);
return merged.map(r => ({ json: r }));
